type Item = { type: string };
type Step = { op: "quote"; items: Item[] };
type Scenario = {
  customer: { yearsWithMHPCO: number };
  steps: Step[];
};

const PROCESSING_FEE = 5;
const FIRST_CONTRACT_SURCHARGE = 10;
const SWORD_BASE = 100;

const quotePremium = (step: Step): number => {
  if (step.items.length === 0) return PROCESSING_FEE;
  return SWORD_BASE + FIRST_CONTRACT_SURCHARGE + PROCESSING_FEE;
};

export const runScenario = (scenario: Scenario): { results: unknown[] } => {
  const results = scenario.steps.map((step) => ({ premium: quotePremium(step) }));
  return { results };
};
